    /**
     * @description Read serializer for combat participants.
     *
     *     Vitals (health, max_health, character_status) are private by default.
     *     Only visible to staff, the scene GM, or the player who owns the
     *     character — same visibility rules as character sheets.
     */
    Participant: {
      readonly id: number;
      readonly character_name: string;
      status?: components['schemas']['ParticipantStatusEnum'];
      /** @description Return current health — only if viewer has permission. */
      readonly health: number | null;
      /** @description Return max health — only if viewer has permission. */
      readonly max_health: number | null;
      /**
       * @description Return a coarse, read-only life status — only if viewer has permission.
       *
       *     Derived at read time from life_state + active conditions + agency (there
       *     is no persisted status field anymore). The richer frontend status surface
       *     is tracked by #521/#522.
       */
      readonly character_status: string | null;
      /**
       * @description Return strain budget (anima pool) — only if viewer owns the PC.
       *
       *     Uses the same vitals-visibility rules as health/status fields.
       *     The frontend's YourTurn strain slider reads this as its max value.
       */
      readonly available_strain: number | null;
      /**
       * @description Return the three fatigue pools (physical/social/mental).
       *
       *     Each pool is ``{"current": N, "capacity": M}``. ``current`` reads the
       *     persisted ``FatiguePool`` row (0 when no row exists yet); ``capacity``
       *     is derived from the character's endurance stats via
       *     ``get_fatigue_capacity``. Gated by the same vitals-visibility rules as
       *     health/strain — outsiders get ``None``.
       *
       *     The frontend's VitalPools component reads this to render fatigue bars
       *     (replacing the ``0/10`` placeholder). See #552.
       */
      readonly fatigue: {
        [key: string]: {
          [key: string]: number;
        };
      } | null;
      /**
       * @description Active conditions on this participant's character ObjectDB.
       *
       *     Public conditions (``is_visible_to_others=True``) are shown to
       *     everyone; hidden conditions only to the character's owner, GMs, or
       *     staff — reusing the same ownership gate as vitals
       *     (``_can_view_vitals``). Ordered by ``display_priority`` (highest
       *     first). No conditions → ``[]``.
       */
      readonly active_conditions: {
        [key: string]: unknown;
      }[];
      /**
       * @description Direct portrait URL via the primary persona (mirrors OpponentSerializer).
       *
       *     The persona's ``thumbnail_url`` URLField (``""`` when unset); ``None``
       *     when the character has no primary persona.
       */
      readonly thumbnail_url: string | null;
      /**
       * @description PlayerMedia portrait URL via the primary persona's thumbnail.
       *
       *     ``None`` when there is no primary persona or it has no thumbnail.
       */
      readonly thumbnail_media_url: string | null;
    };
    /**
     * @description Read serializer for combat participants.
     *
     *     Vitals (health, max_health, character_status) are private by default.
     *     Only visible to staff, the scene GM, or the player who owns the
     *     character — same visibility rules as character sheets.
     */
    ParticipantRequest: {
      status?: components['schemas']['ParticipantStatusEnum'];
    };
    /**
     * @description * `active` - Active
     *     * `fled` - Fled
     *     * `removed` - Removed
     * @enum {string}
     */
    ParticipantStatusEnum: 'active' | 'fled' | 'removed';
    /**
     * @description * `critical` - Critical
     *     * `important` - Important
     *     * `optional` - Optional
     * @enum {string}
     */
    ParticipationLevelEnum: 'critical' | 'important' | 'optional';
    /**
     * @description * `SINGLE_ACTOR` - Single Actor
     *     * `FORMATION` - Formation (all must accept, ≥2)
     *     * `INDUCTION` - Induction (majority of respondents)
     *     * `BILATERAL` - Bilateral (exactly 2, both must accept)
     * @enum {string}
     */
    ParticipationRuleEnum: 'SINGLE_ACTOR' | 'FORMATION' | 'INDUCTION' | 'BILATERAL';
    /** @description Full serializer for Beat including all Phase 2 predicate config fields. */
    PatchedBeatRequest: {
      episode?: number;
      /** @default gm_marked */
      predicate_type: components['schemas']['PredicateTypeEnum'];
      /**
       * @description The story's current outcome on this beat — a single shared value across the story's progression (the owning character for CHARACTER scope, the group for GROUP scope, the world for GLOBAL scope). A story has exactly one progression trail, so this field represents the whole story's state, not per-character state. Historical per-character contributions live in BeatCompletion.
       *
       *     * `unsatisfied` - Unsatisfied
       *     * `success` - Success
       *     * `failure` - Failure
       *     * `expired` - Expired
       *     * `pending_gm_review` - Pending GM review
       */
      outcome?: components['schemas']['OutcomeEnum'];
      visibility?: components['schemas']['BeatVisibilityEnum'];
      /** @description Author/Lead GM/staff view: real predicate + meaning. */
      internal_description?: string;
      /** @description Shown while active (if visibility=HINTED or VISIBLE). */
      player_hint?: string;
      /** @description Shown in story log after beat completes. */
      player_resolution_text?: string;
      order?: number;
      kind?: components['schemas']['BeatKindEnum'];
      /** @description False = Tangent: recorded for history, never gates a transition. */
      advances?: boolean;
      /** @description Plain risk number. Meaning/names assigned later with the consequence work. Authoring trust-gated in the serializer. */
      risk?: number;
      /** @description For CHARACTER_LEVEL_AT_LEAST predicates. */
      required_level?: number | null;
      /** @description For ACHIEVEMENT_HELD predicates. */
      required_achievement?: number | null;
      /** @description For CONDITION_HELD predicates. */
      required_condition_template?: number | null;
      /** @description For CODEX_ENTRY_UNLOCKED predicates. */
      required_codex_entry?: number | null;
      /** @description For STORY_AT_MILESTONE predicates. */
      referenced_story?: number | null;
      /**
       * @description Which kind of milestone to check on referenced_story.
       *
       *     * `story_resolved` - Story resolved
       *     * `chapter_reached` - Chapter reached or passed
       *     * `episode_reached` - Episode reached or passed
       */
      referenced_milestone_type?:
        | components['schemas']['ReferencedMilestoneTypeEnum']
        | components['schemas']['BlankEnum'];
      /** @description For referenced_milestone_type=CHAPTER_REACHED. */
      referenced_chapter?: number | null;
      /** @description For referenced_milestone_type=EPISODE_REACHED. */
      referenced_episode?: number | null;
      /** @description For AGGREGATE_THRESHOLD predicates — total contribution points required. */
      required_points?: number | null;
      /** @description Lead GM may flag this beat to be claimable by Assistant GMs. */
      agm_eligible?: boolean;
      /**
       * Format: date-time
       * @description Optional wall-clock deadline. Expiry handling deferred to Phase 3+.
       */
      deadline?: string | null;
      /** @description ConsequencePool to fire when this beat resolves SUCCESS. */
      success_consequences?: number | null;
      /** @description ConsequencePool to fire when this beat resolves FAILURE. */
      failure_consequences?: number | null;
      /** @description ConsequencePool to fire when this beat resolves EXPIRED. */
      expired_consequences?: number | null;
    };
